import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Wushan","description":"A food guide for Wushan Campus","frontmatter":{"lang":"en-US","title":"Wushan","description":"A food guide for Wushan Campus","llm_translated":true},"headers":[],"relativePath":"en/life/eat/wushan.md","filePath":"en/life/eat/wushan.md","lastUpdated":1784829332000}`),a={name:`en/life/eat/wushan.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/life/eat/wushan.md for this page in Markdown format</div><h1 id="wushan-food-guide" tabindex="-1">Wushan Food Guide <a class="header-anchor" href="#wushan-food-guide" aria-label="Permalink to “Wushan Food Guide”">​</a></h1><p>Editor: BayoneT</p><p>This guide is highly subjective and for reference only. Restaurants I&#39;ve heard about but haven&#39;t been to will be marked with <code>code blocks</code>. There are several major shopping complexes near Wushan, and the restaurants covered in this article are basically distributed around them. I weigh about 94 kg, so I eat quite a lot, and my spending is higher than average. Also, unless it&#39;s a restaurant&#39;s specialty dish, I prioritize meat over veggies. Generally speaking, chain restaurants like Saizeriya and KFC are not listed here due to their standardization, but if I encounter particularly bad service or a unique experience, I&#39;ll point it out separately.</p><h2 id="scoring-criteria" tabindex="-1">Scoring Criteria: <a class="header-anchor" href="#scoring-criteria" aria-label="Permalink to “Scoring Criteria:”">​</a></h2><p><strong>Service &amp; Experience</strong>:</p><p>Service is an important part of dining out. Error-free service is the basic requirement for a restaurant. Reference: Restaurants where ordering and checkout are smooth, serving speed is normal, and staff attitude is proper, or well-managed QR code ordering restaurants start scoring from 8.</p><p><strong>Decor &amp; Environment</strong>:</p><p>Having your elbows stick to the table or being in a place that&#39;s too bright or too dark all the time is quite annoying. A restaurant should have lighting that fits its theme or atmosphere and keep the tables and chairs clean and tidy.</p><p>Reference: Restaurants using steel pipes and plywood tables and chairs (basically no themed decoration), with tables basically free of stickiness and stains, start scoring from 7.</p><p><strong>Overall Rating</strong>:</p><p>A very subjective score. Even if a restaurant&#39;s decor and service are less than satisfactory, if it offers good value for money (e.g., great tasting or very affordable &quot;hole-in-the-wall&quot; joints), it can get a high score here.</p><h2 id="near-wushan-campus" tabindex="-1">Near Wushan Campus <a class="header-anchor" href="#near-wushan-campus" aria-label="Permalink to “Near Wushan Campus”">​</a></h2><p>Exiting through the small east gate (the small gate adjacent to SC Agricultural University), here are the restaurants I&#39;ve been to:</p><h3 id="northeast-chinese-dumplings-dongbei-shuijiao" tabindex="-1">Northeast Chinese Dumplings (Dongbei Shuijiao) <a class="header-anchor" href="#northeast-chinese-dumplings-dongbei-shuijiao" aria-label="Permalink to “Northeast Chinese Dumplings (Dongbei Shuijiao)”">​</a></h3><p>Category: Korean/Northeast Chinese cuisine</p><ul><li>Avg. cost: 40 RMB (cold noodles or dumplings + a cold dish)</li><li>Service &amp; Experience: 7/10 -- Occasionally order but food never comes</li><li>Decor &amp; Environment: 7/10 -- Normal restaurant decor, average level</li><li>Overall Rating: 6.5/10 -- Some dishes clearly use pre-made ingredients</li><li>Recommended: Korean cold noodles, cold mixed century eggs, braised pork bones</li><li>Not recommended: Pork knuckle (pre-made), &quot;King Crab&quot; noodles (too much starch in the crab sticks)</li><li>Route: Exit the small east gate, go downhill and turn right. Don&#39;t cross the road.</li></ul><h3 id="chaoshan-rice-noodles-multigrain-pancakes-chaoshan-guotiao-yu-zaliang-jianbing" tabindex="-1">Chaoshan Rice Noodles &amp; Multigrain Pancakes (Chaoshan Guotiao yu Zaliang Jianbing) <a class="header-anchor" href="#chaoshan-rice-noodles-multigrain-pancakes-chaoshan-guotiao-yu-zaliang-jianbing" aria-label="Permalink to “Chaoshan Rice Noodles &amp; Multigrain Pancakes (Chaoshan Guotiao yu Zaliang Jianbing)”">​</a></h3><p><strong>This shop seems to have changed owners</strong>.</p><p>Category: Mixed (rice noodles, stir-fry, Chinese pastries)</p><ul><li>Avg. cost: Less than 20 RMB (rice noodles or a pair of baked flatbreads)</li><li>Service &amp; Experience: 6.5/10 -- Since they removed the dedicated cashier, orders often get missed.</li><li>Decor &amp; Environment: 5.5/10 -- The interior is dim, tables are sticky, stuffy, and <strong>they often fry up chili peppers</strong>. Also, they removed the air conditioning. However, there are street-side seats.</li><li>Overall Rating: 7/10 -- Generous meat portions, free refills on rice noodles, great value.</li><li>Recommended: Pork and lean meatball soup with rice noodles, baked flatbread (though the flatbread seems to be gone now)</li><li>Not recommended: Any stir-fried rice noodles (not skilled enough, lots of noodles stuck together), multigrain pancakes (too plain without an extra egg)</li><li>Route: Exit the small east gate, go downhill and turn right. Don&#39;t cross the road.</li></ul><h3 id="pig-trotter-rice-zhu-jiao-fan" tabindex="-1">Pig Trotter Rice (Zhu Jiao Fan) <a class="header-anchor" href="#pig-trotter-rice-zhu-jiao-fan" aria-label="Permalink to “Pig Trotter Rice (Zhu Jiao Fan)”">​</a></h3><ul><li>Category: Pig trotter rice</li><li>Avg. cost: About 25 RMB (roasted meat combo rice)</li><li>Service &amp; Experience: 8/10 -- Sliced to order on the spot.</li><li>Decor &amp; Environment: 6.5/10 -- Located in the mall&#39;s food court area, sharing tables and chairs with other shops. Tables are a bit sticky even with frequent wiping. Overall lighting is fine.</li><li>Overall Rating: 7/10 -- Acceptable meat portions, comes with complimentary chicken bone soup and self-serve rice refills.</li><li>Recommended/Not recommended: I haven&#39;t been to this shop much, and there are many similar places, so no strong impression.</li><li>Route: Cross the road from the small east gate, turn left at the supermarket checkout exit.</li></ul><h3 id="jinling-pastry-jinling-bingye" tabindex="-1">Jinling Pastry (Jinling Bingye) <a class="header-anchor" href="#jinling-pastry-jinling-bingye" aria-label="Permalink to “Jinling Pastry (Jinling Bingye)”">​</a></h3><ul><li>Category: Chinese pastries</li><li>Avg. cost: 10-15 RMB (egg pancake, sauce-flavored pancake, scallion pancake, or various stuffed pies)</li><li>Service &amp; Experience: 8/10 -- Made and weighed to order</li><li>Decor &amp; Environment: No dining area.</li><li>Overall Rating: 7.5/10 -- Amazing value for money</li><li>Recommended: Egg pancake</li><li>Not recommended: Nothing strongly not recommended.</li><li>Route: Across the road from the small east gate, next to the metro station.</li></ul><h3 id="yinji-rice-noodle-roll-yinji-changfen-dian" tabindex="-1">Yinji Rice Noodle Roll (Yinji Changfen Dian) <a class="header-anchor" href="#yinji-rice-noodle-roll-yinji-changfen-dian" aria-label="Permalink to “Yinji Rice Noodle Roll (Yinji Changfen Dian)”">​</a></h3><p><strong>Note: This is a restaurant <em>not recommended</em> to visit.</strong></p><ul><li>Category: Cantonese cuisine (rice noodle rolls, soup noodles, and congee)</li><li>Avg. cost: 20 RMB (lunch, rice noodle roll with extra toppings + Cantonese-style congee)</li><li>Service &amp; Experience: 8/10 -- QR code ordering</li><li>Decor &amp; Environment: 6.5/10 -- Although clean and tidy, the shop is too narrow, the tables are very small, and it feels quite cramped when crowded.</li><li>Overall Rating: 5/10 -- <strong>You call that a rice noodle roll?</strong></li></ul><h3 id="nieh-liao-mie-liao" tabindex="-1">Nieh Liao (Mie Liao) <a class="header-anchor" href="#nieh-liao-mie-liao" aria-label="Permalink to “Nieh Liao (Mie Liao)”">​</a></h3><ul><li>Category: Thai and Southeast Asian cuisine</li><li>Avg. cost: 40 RMB (group) - 50 RMB (solo, 1 fried rice + shrimp chips + cold drink)</li><li>Service &amp; Experience: 7.5/10 -- QR code ordering, <strong>no free napkins provided</strong>.</li><li>Decor &amp; Environment: Indoor 8.5/10 (good lighting, clean seats) Outdoor 7.5/10 (mosquitoes in summer)</li><li>Other notes: <strong>Closed on Mondays for pest control</strong>. During peak hours (after 11:30 AM, after 5:30 PM), you must queue and reserve in advance, otherwise the wait can be long (about half an hour)</li><li>Overall Rating: 9/10</li><li>Recommended: Charcoal-grilled pork neck, pineapple fried rice</li><li>Not recommended: None</li><li>Route: Use navigation maps (</li></ul><h3 id="one-meter-chicken-yimi-jirou" tabindex="-1">One Meter Chicken (Yimi Jirou) <a class="header-anchor" href="#one-meter-chicken-yimi-jirou" aria-label="Permalink to “One Meter Chicken (Yimi Jirou)”">​</a></h3><p><strong>Note: This is a restaurant <em>not recommended</em> to visit, but my experience <em>differs significantly</em> from others -- some people have good things to say about it.</strong></p><ul><li>Category: Korean cuisine (stone pot rice) and modern Korean fast food (fried chicken, etc.)</li><li>Avg. cost: About 25 RMB (a bowl of stone pot rice)</li><li>Service &amp; Experience: 8/10 -- QR code ordering</li><li>Decor &amp; Environment: No rating. I went right when the dinner service opened.</li><li>Overall Rating: 5/10 -- <strong>Pre-made food.</strong></li><li>Route: Next to McDonald&#39;s outside the small east gate.</li></ul><h3 id="dagang-xianmiao-roast-chicken-dagang-xianmiao-shaoji" tabindex="-1">Dagang Xianmiao Roast Chicken (Dagang Xianmiao Shaoji) <a class="header-anchor" href="#dagang-xianmiao-roast-chicken-dagang-xianmiao-shaoji" aria-label="Permalink to “Dagang Xianmiao Roast Chicken (Dagang Xianmiao Shaoji)”">​</a></h3><ul><li>Category: Xianmiao roast chicken (and honey-glazed ribs)</li><li>Avg. cost: 40-50 RMB -- <strong>Not recommended for solo dining</strong></li><li>Service &amp; Experience: 8/10 -- QR code ordering</li><li>Decor &amp; Environment: 7/10 -- Typical Xianmiao roast chicken style rough decor (cement floor, brick or matte dark ceramic tile floor, dim interior), so no deduction.</li><li>Overall Rating: 7/10</li><li>Recommended: Honey-glazed ribs</li><li>Route: Follow your navigation map. Note: This shop doesn&#39;t have a separate entrance; it shares a stairwell entrance with another restaurant in the same building.</li></ul><h3 id="wuwan-beef-rice-noodles-wuwan-niurou-guotiao" tabindex="-1">Wùwǎn Beef Rice Noodles (Wuwan Niurou Guotiao) <a class="header-anchor" href="#wuwan-beef-rice-noodles-wuwan-niurou-guotiao" aria-label="Permalink to “Wùwǎn Beef Rice Noodles (Wuwan Niurou Guotiao)”">​</a></h3><p><strong>Note: This is a restaurant <em>not recommended</em> to visit.</strong></p><ul><li>Category: Teochew cuisine (beef balls and rice noodles)</li><li>Avg. cost: About 25 RMB (a bowl of rice noodles)</li><li>Service &amp; Experience: 8/10 -- QR code ordering</li><li>Decor &amp; Environment: 7.5/10 (highly subjective) -- This place uses trendy internet-famous decor, but the shop layout is oddly shaped, making it feel a bit disjointed. Also, I don&#39;t like internet-famous style decor.</li><li>Overall Rating: 5.5/10 -- Too few meatballs. Also, some crunchy vegetable topping is cut too finely, completely clashing with the texture of the other ingredients.</li><li>Route: Exit the north area&#39;s south gate or the south area&#39;s north gate, head downhill along Dongguan Village Road to the fork.</li></ul><h2 id="tianhe-xintiandi-and-the-changban-urban-village-across-the-street" tabindex="-1">Tianhe Xintiandi and the Changban Urban Village Across the Street <a class="header-anchor" href="#tianhe-xintiandi-and-the-changban-urban-village-across-the-street" aria-label="Permalink to “Tianhe Xintiandi and the Changban Urban Village Across the Street”">​</a></h2><h3 id="a-xing-rice-balls-axing-fantuan" tabindex="-1">A Xing Rice Balls (Axing Fantuan) <a class="header-anchor" href="#a-xing-rice-balls-axing-fantuan" aria-label="Permalink to “A Xing Rice Balls (Axing Fantuan)”">​</a></h3><p><strong>Note: This is a restaurant <em>not recommended</em> to visit.</strong></p><ul><li>Category: Japanese cuisine (sushi and seaweed rolls)</li><li>Avg. cost: About 20 RMB (large seaweed roll)</li><li>Service &amp; Experience: 8/10 -- Made to order, wrapped on the spot</li><li>Decor &amp; Environment: No dining area</li><li>Overall Rating: 3/10 -- <strong>It&#39;s not even tasty. Who taught you to put cucumber in a <em>hot</em> rice ball <em>and pair it with meat floss</em>???</strong></li><li>Located at Tianhe Xintiandi B1 level.</li></ul><h3 id="pelicana-fried-chicken-baijia-zhaji" tabindex="-1">Pelicana Fried Chicken (Baijia Zhaji) <a class="header-anchor" href="#pelicana-fried-chicken-baijia-zhaji" aria-label="Permalink to “Pelicana Fried Chicken (Baijia Zhaji)”">​</a></h3><ul><li>Category: Korean fast food (fried items, fried chicken, beer)</li><li>Avg. cost: About 30 RMB</li><li>Service &amp; Experience: 8/10 -- QR code ordering</li><li>Decor &amp; Environment: 8/10 -- Clean and tidy, with some atmosphere</li><li>Overall Rating: 8/10</li><li>Recommended: Passion fruit flavored beer, cheese fried chicken</li><li>Located outside Tianhe Xintiandi.</li></ul><h3 id="stone-mill-rice-noodle-roll-shimo-changfen" tabindex="-1">Stone Mill Rice Noodle Roll (Shimo Changfen) <a class="header-anchor" href="#stone-mill-rice-noodle-roll-shimo-changfen" aria-label="Permalink to “Stone Mill Rice Noodle Roll (Shimo Changfen)”">​</a></h3><ul><li>Category: Cantonese cuisine (rice noodle rolls and congee)</li><li>Avg. cost: About 15 RMB (lunch, 2 rice noodle rolls and a bowl of congee)</li><li>Service &amp; Experience: 8/10 -- Order in person</li><li>Decor &amp; Environment: 6.5/10 -- Tables slightly sticky</li><li>Overall Rating: 7.5/10 -- Good value.</li><li>Note: This shop uses soy sauce with garlic.</li><li>Route: No navigation route. Search for &quot;Yunfu Traditional Stone Mill Rice Noodle Roll&quot; on Amap, then find the one with a roast chicken stall next to it.</li></ul><h1 id="metro-accessible" tabindex="-1">Metro Accessible <a class="header-anchor" href="#metro-accessible" aria-label="Permalink to “Metro Accessible”">​</a></h1><h2 id="gangding-station-tianyu-plaza" tabindex="-1">Gangding Station: Tianyu Plaza <a class="header-anchor" href="#gangding-station-tianyu-plaza" aria-label="Permalink to “Gangding Station: Tianyu Plaza”">​</a></h2><h3 id="tonkatsu-win-tunsheng" tabindex="-1">Tonkatsu Win (Tunsheng) <a class="header-anchor" href="#tonkatsu-win-tunsheng" aria-label="Permalink to “Tonkatsu Win (Tunsheng)”">​</a></h3><ul><li>Category: Japanese cuisine (fried pork cutlet)</li><li>Avg. cost: About 50 RMB (a serving of pork cutlet rice)</li><li>Service &amp; Experience: 8/10 -- QR code ordering <strong>Recommended to use the set meal coupons on Meituan mini-program</strong></li><li>Decor &amp; Environment: 7.5/10 -- Modern Japanese restaurant decor (long tables and individual seats)</li><li>Overall Rating: 7.5/10 -- Delicious!</li><li>This place offers free refills of the side dishes included in the set meal (i.e., anything in the small dishes served alongside the main plate), such as shredded cabbage, mashed potato, pickled radish, and miso soup. Rice refills are also free.</li><li>Route: Exit Gangding Station at Exit C, cross the footbridge and turn right toward the fountain. Next to the &quot;Coffee Alchemy&quot; storefront there is an entrance to the B1 level &quot;Youjiandi,&quot; push the door and enter. Once in B1, another coffee shop will be on your right, and the pork cutlet place is behind it.</li></ul><h3 id="grandpa-beef-brisket-rice-nanye-niunan-fan" tabindex="-1">Grandpa Beef Brisket Rice (Nanye Niunan Fan) <a class="header-anchor" href="#grandpa-beef-brisket-rice-nanye-niunan-fan" aria-label="Permalink to “Grandpa Beef Brisket Rice (Nanye Niunan Fan)”">​</a></h3><p><strong>Note: This is a restaurant <em>not recommended</em> to visit.</strong></p><p>Also, <em>this is a chain restaurant.</em></p><ul><li>Category: Chinese cuisine (beef brisket rice bowl)</li><li>Avg. cost: About 25 RMB (a beef brisket rice set meal)</li><li>Service &amp; Experience: 8/10 -- QR code ordering</li><li>Decor &amp; Environment: 6.5/10 -- They couldn&#39;t even be bothered to separate the dining area from the mall corridor</li><li>Overall Rating: 2/10 -- <strong>Pre-made food.</strong></li><li>Why is it rated even lower than A Xing Rice Balls? Because their red bean dessert soup <strong>had absorbed odors from other items in the cold storage.</strong></li><li>Location: Same as Tonkatsu Win, Tianyu Plaza Youjiandi.</li></ul><h2 id="the-black-people-district-xiaobei-taojin" tabindex="-1">The &quot;Black People District&quot; (Xiaobei/Taojin) <a class="header-anchor" href="#the-black-people-district-xiaobei-taojin" aria-label="Permalink to “The &quot;Black People District&quot; (Xiaobei/Taojin)”">​</a></h2><p>This area basically <strong>only serves halal cuisine</strong>. Please respect local residents&#39; customs and do not bring alcohol or pork products.</p><h2 id="xiaobei-metro-station" tabindex="-1">Xiaobei (Metro Station) <a class="header-anchor" href="#xiaobei-metro-station" aria-label="Permalink to “Xiaobei (Metro Station)”">​</a></h2><h3 id="baohan-straight-street-snack-street" tabindex="-1">Baohan Straight Street (Snack Street) <a class="header-anchor" href="#baohan-straight-street-snack-street" aria-label="Permalink to “Baohan Straight Street (Snack Street)”">​</a></h3><p>Avg. cost: Listed in the table. (Naan, baked stuffed buns, &quot;shawarma,&quot; yogurt)</p><table tabindex="0"><thead><tr><th>Dish</th><th>Shawarma (Beef)</th><th>Shawarma (Chicken)</th><th>Naan (~20cm diameter)</th><th>Baked Stuffed Bun</th></tr></thead><tbody><tr><td><strong>Price</strong></td><td>35</td><td>30</td><td>5-10</td><td>5</td></tr></tbody></table><p>Also, try the &quot;milk skin&quot; dessert or &quot;kvas&quot; fermented drink (non-alcoholic). Only recommended to buy honey-flavored &quot;kvas.&quot; Don&#39;t rush -- it&#39;s best to walk through the entire Baohan Straight Street first before deciding what to eat, otherwise you&#39;ll easily fill up on flatbread.</p><p>Overall Rating: 6.5/10</p><h3 id="sadda-restaurant-name-registered-on-amap" tabindex="-1">Sadda Restaurant (Name registered on Amap) <a class="header-anchor" href="#sadda-restaurant-name-registered-on-amap" aria-label="Permalink to “Sadda Restaurant (Name registered on Amap)”">​</a></h3><p>The storefront sign says <strong>Sadda Restaurant</strong></p><ul><li>Category: Middle Eastern cuisine</li><li>Avg. cost: 70 RMB (4 people, flatbread, milk tea, main dishes, sides) -- <strong>Not recommended for solo dining.</strong></li><li><strong>Note: This place also serves Persian-style hookah separately. But I don&#39;t smoke, so no comment.</strong></li><li>Also, whether it&#39;s flatbread or pilaf as the staple, <strong>it&#39;s extremely messy to eat</strong>. If you&#39;re on a date, <strong>don&#39;t come here.</strong></li><li>Service &amp; Experience: 5/10 -- You have to actively flag down the waitstaff. It&#39;s unclear whether bottled water is charged or not, and they often forget to serve the soup. Also, billing is very casual -- the same dish is sometimes recorded under different names.</li><li>Decor &amp; Environment: 6/10 -- Lots of people smoking hookah gather outside the shop, giving off a gangster-ish vibe that&#39;s a bit unsettling. No tablecloths inside; everything uses plastic coverings.</li><li>Overall Rating: 8/10</li><li>Date Rating: 5/10</li><li>Despite the less-than-ideal service and decor, this place offers incredible value and great taste.</li><li>Recommended dishes: Roasted lamb chops, Yemeni flatbread (~60cm diameter), beef clay pot, stir-fried white beans.</li><li>Not recommended: Any Chinese dishes on the menu.</li></ul><h3 id="mocha-coffee-moka-kafei" tabindex="-1">Mocha Coffee (Moka Kafei) <a class="header-anchor" href="#mocha-coffee-moka-kafei" aria-label="Permalink to “Mocha Coffee (Moka Kafei)”">​</a></h3><ul><li>Category: Coffee shop, also serves main dishes. Also has fried fish, fries, and other Western fast food.</li><li>Avg. cost: 50 RMB (shawarma and a plate of yellow rice. These two are actually quite a lot -- I was stuffed.)</li><li>Service &amp; Experience: 8/10 -- QR code ordering</li><li>Decor &amp; Environment: Indoor 7/10, tables slightly sticky; haven&#39;t been outside</li><li>Overall Rating: 6/10 -- Not worth going out of your way unless you&#39;re having coffee and eating on the side. And I&#39;m not really a coffee person.</li></ul><h3 id="beirut-li-beitrut" tabindex="-1">Beirut LI BEITRUT <a class="header-anchor" href="#beirut-li-beitrut" aria-label="Permalink to “Beirut LI BEITRUT”">​</a></h3><ul><li>Category: Middle Eastern cuisine (Lebanese)</li><li>Avg. cost: 65 RMB (grilled meat set meal, didn&#39;t get full. We went back to our dorm and had barbecue in Changban that night.)</li><li>Service &amp; Experience: 5/10 -- Foreign waitstaff, can only communicate using &quot;this&quot; and hand gestures. Also, orders got missed due to miscommunication.</li><li>Decor &amp; Environment: 8.5/10 -- Quite elegant</li><li>Overall Rating: Eating 5/10 -- Date 8/10 -- Beautiful decor, great taste, but the portions are too small. This place is more suitable for taking your date out rather than bringing your whole dorm to chow down. <strong>Clearly I don&#39;t have a girlfriend. Otherwise I wouldn&#39;t be writing this guide.</strong></li><li></li></ul><h2 id="taojin-metro-station" tabindex="-1">Taojin (Metro Station) <a class="header-anchor" href="#taojin-metro-station" aria-label="Permalink to “Taojin (Metro Station)”">​</a></h2><h3 id="armada-restaurant-ameida-canting" tabindex="-1">Armada Restaurant (Ameida Canting) <a class="header-anchor" href="#armada-restaurant-ameida-canting" aria-label="Permalink to “Armada Restaurant (Ameida Canting)”">​</a></h3><ul><li>Category: Turkish cuisine</li><li>Avg. cost: About 90 RMB (3 people eating a 4-person set meal) -- <strong>Not recommended for solo dining.</strong> Recommended to use Meituan set meal coupons to complement your order, <strong>don&#39;t order a la carte.</strong></li><li><strong>Note: This place also serves Persian-style hookah.</strong></li><li>Service &amp; Experience: 8/10 -- QR code ordering and coupon redemption</li><li>Decor &amp; Environment: 10/10 -- Located on the 3rd floor of a hotel, the entrance is clean and tidy, and the decor is exquisite and splendid.</li><li>Overall Rating: 10/10 -- One of my favorite restaurants.</li><li>Note: The yogurt here uses a special yeast -- it&#39;s not sweet and has a peculiar smell. Don&#39;t order it unless you really want to try it.</li></ul><h2 id="scattered-restaurants" tabindex="-1">Scattered Restaurants <a class="header-anchor" href="#scattered-restaurants" aria-label="Permalink to “Scattered Restaurants”">​</a></h2><h3 id="you-hui-youhui" tabindex="-1">You Hui (Youhui) <a class="header-anchor" href="#you-hui-youhui" aria-label="Permalink to “You Hui (Youhui)”">​</a></h3><p><strong>This is a chain restaurant.</strong></p><ul><li>Category: Japanese cuisine (fried pork cutlet)</li><li>Avg. cost: About 50 RMB (a serving of pork cutlet rice) / About 40 RMB (weekday special set meal)</li><li>Service &amp; Experience: 8/10 -- Order in person and queue. Note: It seems like you can&#39;t take a number online here; you have to queue in person.</li><li>Decor &amp; Environment: 7.5/10 -- Solid wood furniture</li><li>Overall Rating: 7.5/10 -- Delicious!</li><li>This place offers free refills of the side dishes included in the set meal (i.e., anything in the small dishes served alongside the main plate), such as shredded cabbage, mashed potato, pickled radish, and miso soup. Rice refills are also free.</li><li>Basically the same as Tonkatsu Win.</li><li>Location: Branch locations in Shiqiaoqiao and Linhexi</li></ul><h3 id="katyusha-russian-restaurant-kaqiusha-eshi-canting" tabindex="-1">Katyusha Russian Restaurant (Kaqiusha Eshi Canting) <a class="header-anchor" href="#katyusha-russian-restaurant-kaqiusha-eshi-canting" aria-label="Permalink to “Katyusha Russian Restaurant (Kaqiusha Eshi Canting)”">​</a></h3><ul><li>Category: Russian and Eastern European cuisine</li><li>Avg. cost: About 100 RMB (4 people, cold dishes, staple food, main dishes, salad, and soup) -- <strong>Not recommended for solo dining</strong></li><li>Service &amp; Experience: 10/10 -- Order in person. They&#39;ll also give you an extra cake on your birthday.</li><li>Decor &amp; Environment: 10/10 -- Candle holders, beautiful tablecloths, and great ambient lighting</li><li>Overall Rating: 10/10 -- One of my favorite restaurants.</li><li>Other notes: Not recommended to order too many dishes at once. They&#39;ve basically done no localization -- borscht, beef stew, etc., all remain heavy on oil and salt. Cheese curd dumplings <strong>are not that good</strong> -- unless you really want to try, don&#39;t order any of their Eastern European-style &quot;dumpling&quot; pastries.</li><li>Location: Linhexi</li></ul><h3 id="indian-restaurant-name-registered-on-amap" tabindex="-1">Indian Restaurant (Name registered on Amap) <a class="header-anchor" href="#indian-restaurant-name-registered-on-amap" aria-label="Permalink to “Indian Restaurant (Name registered on Amap)”">​</a></h3><p><strong>The storefront sign says &quot;Shahenshah&quot;</strong></p><ul><li>Category: Indian cuisine</li><li>Avg. cost: About 80 RMB (a cup of ginger milk tea, a set meal plus an extra flatbread)</li><li>Service &amp; Experience: 6.5/10 -- The boss doesn&#39;t understand Chinese, communication mainly goes through the cooking auntie, and her Mandarin is not very fluent either</li><li>Decor &amp; Environment: 8.5/10 -- They&#39;ve tried their best to recreate an Indian vibe while keeping it hygienic</li><li>Overall Rating: 7.5/10 -- Doesn&#39;t fill you up much. If you&#39;re just looking to experience Indian cuisine, it can get 8 points.</li><li>Location: Longkou West, or a 25-minute bike ride.</li></ul><h3 id="pipa-pipa-kitchen-pizza-lab-pipa-pipa-xiaochu-pisa-yanjiusuo" tabindex="-1">PIPA Pipa Kitchen Pizza Lab (PIPA Pipa Xiaochu Pisa Yanjiusuo) <a class="header-anchor" href="#pipa-pipa-kitchen-pizza-lab-pipa-pipa-xiaochu-pisa-yanjiusuo" aria-label="Permalink to “PIPA Pipa Kitchen Pizza Lab (PIPA Pipa Xiaochu Pisa Yanjiusuo)”">​</a></h3><ul><li>Category: Pizza place</li><li>Avg. cost: About 70 RMB (pizza + soup)</li><li>Service &amp; Experience: 7/10 -- QR code ordering</li><li>Decor &amp; Environment: 7/10 -- The shop is nicely decorated, <strong>it&#39;s just way too damn far from the metro station, and there are no shared bikes to be found nearby.</strong></li><li>Overall Rating: 8.5/10 -- This place uses a real wood-fired oven to bake pizza (apparently with some Italian certification). Worth a try if you&#39;ve never had it, but after going once for the experience, you&#39;ll seriously reconsider whether you want to sit on the metro for half an hour and then walk another long way.</li><li>Location: Diyuan Station Exit C, then walk 1.1 km.</li></ul>`,83)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};